const event = $input.first().json;

// --- CLASSIFICAR TIPO DE EVENTO ---
const isCancelled = event.status === 'cancelled';

// Se cancelado, dados minimos
if (isCancelled) {
  const id = event.id || '';
  // Tentar extrair telefone mesmo em cancelamento
  const rawDesc = (event.description || '').replace(/<[^>]*>/g, ' ').replace(/&nbsp;/g, ' ');
  const telMatch = rawDesc.match(/[\d\s\(\)\+\-]{10,}/);
  let telefone = telMatch ? telMatch[0].replace(/\D/g, '') : '';
  if (telefone.length === 10 || telefone.length === 11) telefone = '55' + telefone;

  const lines = rawDesc.split(/[\n\r]+/).map(l => l.trim()).filter(l => l.length > 0);
  let nome = '';
  for (const line of lines) {
    if (!/booked by/i.test(line) && !line.includes('@') && !line.includes('http') && !/^[\d\s\(\)\+\-]+$/.test(line) && line.length >= 2 && line.length <= 100) {
      nome = line; break;
    }
  }
  const primeiroNome = nome.split(' ')[0] || '';

  const msgCancelamento = telefone ? `Ol\u00e1 ${primeiroNome || 'tudo bem'}? \u{274C}\n\nSeu agendamento foi *cancelado*.\n\nSe desejar reagendar, acesse:\n\u{1F4C5} https://calendar.app.google/19uX8hWQsbfrmAM86\n\nAtenciosamente\n*Rog\u00e9rio Borges - RNB Solu\u00e7\u00f5es*` : '';

  return [{ json: {
    id_agendamento: id,
    status_evento: 'Cancelado',
    data_cancelamento: new Date().toISOString().split('T')[0],
    number: telefone,
    nome_lead: nome,
    telefone_lead: telefone,
    msgPrincipal: msgCancelamento,
    isCancelled: true
  }}];
}

// --- PARSING ROBUSTO (regex) ---
const rawDesc = (event.description || '').replace(/<[^>]*>/g, ' ').replace(/&nbsp;/g, ' ');
const lines = rawDesc.split(/[\n\r]+/).map(l => l.trim()).filter(l => l.length > 0);

let nome = '';
let email = '';
let telefone = '';

for (const line of lines) {
  if (!email && /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(line)) {
    email = line;
  } else if (!telefone && /^[\d\s\(\)\+\-]{8,}$/.test(line)) {
    telefone = line.replace(/\D/g, '');
  } else if (!nome && !/booked by/i.test(line) && !line.includes('http') && line.length >= 2 && line.length <= 100) {
    nome = line;
  }
}

// Fallback: attendees
const attendees = (event.attendees || []).filter(a => a.email !== event.creator?.email && a.email !== event.organizer?.email);
if (!email && attendees.length > 0) {
  email = attendees[0].email || '';
  nome = nome || attendees[0].displayName || email.split('@')[0];
}

if (telefone) {
  if (telefone.length === 10 || telefone.length === 11) telefone = '55' + telefone;
  if (telefone.length < 12) return [];
} else {
  return [];
}

// --- DATA/HORA ---
const startRaw = event.start?.dateTime || '';
let dataFmt = '';
let horaFmt = '';
let dataInicio = '';
let horaInicio = '';
let diaSemana = '';

if (startRaw) {
  const dt = new Date(startRaw);
  const dias = ['Domingo','Segunda-feira','Ter\u00e7a-feira','Quarta-feira','Quinta-feira','Sexta-feira','S\u00e1bado'];
  diaSemana = dias[dt.getDay()];
  const dd = String(dt.getDate()).padStart(2,'0');
  const mm = String(dt.getMonth()+1).padStart(2,'0');
  const yyyy = dt.getFullYear();
  const hh = String(dt.getHours()).padStart(2,'0');
  const min = String(dt.getMinutes()).padStart(2,'0');
  dataFmt = `${diaSemana}, ${dd}/${mm}/${yyyy}`;
  horaFmt = `${hh}:${min}h`;
  dataInicio = `${yyyy}-${mm}-${dd}`;
  horaInicio = `${hh}:${min}`;
}

const meetLink = event.hangoutLink || (event.conferenceData?.entryPoints || []).find(e => e.entryPointType === 'video')?.uri || '';
const titulo = event.summary || 'Reuniao';
const primeiroNome = nome.split(' ')[0] || '';
const dataAgendamento = event.created ? event.created.split('T')[0] : new Date().toISOString().split('T')[0];

// --- DETERMINAR SE EH NOVO OU REAGENDAMENTO ---
// Se veio do trigger 'eventUpdated' e nao eh cancelamento, eh reagendamento
// Simplificacao: se o evento ja existia (updated > created + 60s), tratar como reagendamento
const createdMs = event.created ? new Date(event.created).getTime() : 0;
const updatedMs = event.updated ? new Date(event.updated).getTime() : 0;
const isReagendamento = (updatedMs - createdMs) > 60000;

const statusEvento = isReagendamento ? 'Reagendado' : 'Agendamento';

// --- ASSINATURA ---
const assinatura = `---\n\nPrazer, me chamo Rog\u00e9rio e sou Fundador da *RNB Solu\u00e7\u00f5es*, uma startup especializada em desenvolvimento de sistemas e automa\u00e7\u00f5es assistida por Intelig\u00eancia Artificial.\n\nEstou disponibilizando meu contato e minha agenda para podermos marcar um bate papo inicial e assim eu posso entender a sua necessidade e assim ter condi\u00e7\u00f5es de te enviar uma proposta.\n\n*Contato:*\n\u{1F4F1} Celular: (17) 99184-1789\n\u{1F4E7} Email: rogerio@rnbsolucoes.com.br\n\u{1F4C5} Agenda: https://calendar.app.google/19uX8hWQsbfrmAM86\n\n*Saiba mais:*\n\u{1F310} Site: https://www.rnbsolucoes.com.br\n\u{1F4BC} Portf\u00f3lio: https://rogerio.rnbsolucoes.com.br/\n\u{1F517} LinkedIn: https://www.linkedin.com/in/rogerio-rnb-solucoes/\n\nDesde j\u00e1 agrade\u00e7o e fico \u00e0 disposi\u00e7\u00e3o!\n\nAtenciosamente\n*Rog\u00e9rio Borges*`;

// --- MENSAGENS ---
const headerMsg = isReagendamento
  ? `Ol\u00e1 ${primeiroNome}, seu agendamento foi *reagendado*! \u{1F504}`
  : `Ol\u00e1 ${primeiroNome}, seu agendamento est\u00e1 *confirmado*! \u{2705}`;

const msgPrincipal = `${headerMsg}\n\n\u{1F4C5} Data: ${dataFmt}\n\u{23F0} Hor\u00e1rio: ${horaFmt}${meetLink ? `\n\u{1F4BB} Link: ${meetLink}` : ''}\n\n${assinatura}`;

const msgLembrete1h = `Ol\u00e1 ${primeiroNome}! \u{23F3}\n\nSua reuni\u00e3o *${titulo}* come\u00e7a em *1 hora*!\n\n\u{23F0} ${horaFmt}${meetLink ? `\n\u{1F4BB} ${meetLink}` : ''}\n\nNos vemos em breve!\n*Rog\u00e9rio Borges - RNB Solu\u00e7\u00f5es*`;

const msgLembrete30min = `${primeiroNome}, faltam *30 minutos*! \u{1F514}\n\nSua reuni\u00e3o come\u00e7a \u00e0s *${horaFmt}*${meetLink ? `\n\n\u{1F449} Acesse aqui: ${meetLink}` : ''}\n\nTe espero l\u00e1!\n*Rog\u00e9rio Borges*`;

return [{
  json: {
    number: telefone,
    nome_lead: nome,
    primeiroNome,
    email,
    id_agendamento: event.id || '',
    data_agendamento: dataAgendamento,
    status_evento: statusEvento,
    data_de_inicio: dataInicio,
    hora_inicio: horaInicio,
    link_reuniao: meetLink,
    dia_da_semana_evento: diaSemana,
    data_cancelamento: '',
    motivo_cancelamento: '',
    telefone_lead: telefone,
    titulo,
    msgPrincipal,
    msgLembrete1h,
    msgLembrete30min,
    startISO: startRaw,
    isCancelled: false
  }
}];

const data = $('Code - Extrair e Classificar').first().json;
const startISO = data.startISO;
if (!startISO) return [];

const startMs = new Date(startISO).getTime();
const nowMs = Date.now();
const waitMs = startMs - nowMs - (60 * 60 * 1000);

if (waitMs <= 60000) return [];

return [{ json: { ...data, waitSeconds: Math.floor(waitMs / 1000) } }];
